const https = require('https');

function httpsReq(options, body) {
  return new Promise((resolve, reject) => {
    if (Buffer.isBuffer(body)) {
      options.headers = options.headers || {};
      options.headers['Content-Length'] = body.length;
    }
    const req = https.request(options, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(text)); } catch { resolve({ _raw: text }); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const token = $env.SLACK_BOT_TOKEN;
const item = $input.first();
const b64 = item.binary && item.binary.data ? item.binary.data.data : null;

if (!b64) {
  return [{ json: { ...item.json, fileId: null, uploaded: false } }];
}

const buf = Buffer.from(b64, 'base64');
const mimeType = (item.binary.data.mimeType) || 'application/octet-stream';
const fileName = (item.binary.data.fileName) || 'file.bin';

// Step 1: Get upload URL
const body1 = `filename=${encodeURIComponent(fileName)}&length=${buf.length}`;
const urlData = await httpsReq({
  method: 'POST',
  hostname: 'slack.com',
  path: '/api/files.getUploadURLExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/x-www-form-urlencoded',
    'Content-Length': Buffer.byteLength(body1),
  }
}, Buffer.from(body1));

if (!urlData.ok) throw new Error(`getUploadURL failed: ${JSON.stringify(urlData)}`);
const { upload_url, file_id } = urlData;

// Step 2: PUT binary to upload URL
// Parse upload_url without URL class (not available in sandbox)
const urlMatch = upload_url.match(/^https?:\/\/([^\/]+)(\/[^?]*)?(\?.*)?$/);
const uploadHostname = urlMatch[1];
const uploadPath = (urlMatch[2] || '/') + (urlMatch[3] || '');

await httpsReq({
  method: 'PUT',
  hostname: uploadHostname,
  path: uploadPath,
  headers: {
    'Content-Type': mimeType,
    'Content-Length': buf.length,
  }
}, buf);

// Step 3: Complete upload
const channelId = item.json.channelId || '';
const comment = item.json.uploadComment || '';
const completeBody = JSON.stringify({
  files: [{ id: file_id }],
  ...(channelId ? { channel_id: channelId } : {}),
  ...(comment ? { initial_comment: comment } : {}),
});

await httpsReq({
  method: 'POST',
  hostname: 'slack.com',
  path: '/api/files.completeUploadExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(completeBody),
  }
}, Buffer.from(completeBody));

return [{ json: { ...item.json, fileId: file_id, uploaded: true } }];
